const fs = require('fs');
const projRoot = '__PROJECT_ROOT__';
const feed = [];

// Chat history
const histFile = projRoot + '/tasks/.chat-history.jsonl';
if (fs.existsSync(histFile)) {
  const lines = fs.readFileSync(histFile, 'utf8').trim().split(String.fromCharCode(10)).slice(-10);
  for (const line of lines) {
    try {
      const e = JSON.parse(line);
      feed.push({type:'chat', project: e.project, message: e.message, time: e.ts});
    } catch {}
  }
}

// Sort by time desc
feed.sort((a,b) => new Date(b.time) - new Date(a.time));

return [{json:{feed: feed.slice(0, 15), timestamp: new Date().toISOString()}}];
